import{_ as t,o,c as a,a2 as r}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),i={name:"guide/introduction.md"};function n(s,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Tragwerk is a self-hosted platform for hosting PHP applications on your own virtual private server. If you can get a VPS with SSH access from any provider, you can run Tragwerk on it.</p><h2 id="the-problem-it-solves" tabindex="-1">The problem it solves <a class="header-anchor" href="#the-problem-it-solves" aria-label="Permalink to &quot;The problem it solves&quot;">​</a></h2><p>Deploying PHP to a server traditionally means wiring up a web server, a PHP runtime, TLS certificates, databases, and a reverse proxy by hand — and then doing it again for every app and every branch. Managed PaaS offerings remove that toil but take away control and lock you into someone else&#39;s infrastructure.</p><p>Tragwerk sits in the middle: you keep full ownership of the server, but the platform automates the tedious parts. You own the VPS; Tragwerk makes hosting PHP on it simple.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>The heart of Tragwerk is a single configuration file, <code>.tragwerk/config.xml</code>, committed to your repository. Everything flows from it:</p><ol><li><strong>XML config</strong> — you describe your applications, their runtimes, web roots, backing services, routes, and more in <code>.tragwerk/config.xml</code>.</li><li><strong>Docker generation</strong> — Tragwerk reads that XML and generates the complete Docker and docker-compose configuration. You never hand-write YAML.</li><li><strong>Build &amp; run</strong> — on push, Tragwerk builds your Docker image and starts the containers on your VPS. Applications run on FrankenPHP, by default as a drop-in PHP-FPM replacement, with optional worker mode for higher throughput.</li><li><strong>Traefik routing</strong> — Traefik acts as the reverse proxy in front of every app, so multiple applications can share one VPS, each on its own domain with automatic Let&#39;s Encrypt TLS.</li></ol><p>Deployments are <strong>branch-based</strong>: each git branch maps to one isolated <a href="/app/environments">environment</a> with its own containers, services, and domains.</p><div class="info custom-block"><p class="custom-block-title">Why XML?</p><p>Tragwerk&#39;s config is intentionally XML, validated against a schema. That gives you autocomplete and validation in your editor, and a single unambiguous source of truth that generates the underlying Docker setup. See the <a href="/config/overview">XML overview</a>.</p></div><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Tragwerk is a good fit when you:</p><ul><li>already have (or want) your own VPS and prefer self-hosting over a managed PaaS;</li><li>run one or more PHP applications and want per-branch preview environments;</li><li>want declarative, version-controlled infrastructure without writing Docker by hand.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>Learn the vocabulary in <a href="/guide/concepts">Core Concepts</a>.</li><li>Follow the <a href="/guide/getting-started">Getting Started</a> walkthrough.</li><li>Browse the <a href="/config/overview">configuration reference</a>.</li></ul>',15)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
